class Solution:
    def minDiffInBST(self, root: Optional[TreeNode]) -> int:
        self.prev = None
        self.ans = 10**9
        def dfs(n):
            if not n: return
            dfs(n.left)
            if self.prev is not None:
                self.ans = min(self.ans, n.val - self.prev)
            self.prev = n.val
            dfs(n.right)
        dfs(root)
        return self.ans

